#' Prepare a table with results
#'
#' Given results table, prepares APA
#' style tables with results for all analyses
#' of PAW vs. NC contrasts in regressions.
#'
#' @param res List. Tables generated by \code{stat_test}.
#'
#' @returns List of formatted {gt} tables.
#'
#' @seealso [table_single()] makes a single table.
#'
#' @export
table_results <- function(res) {
  t0 <- lapply(res, function(i) {
    i$mPA
  })
  titles <- list(
    unadjusted = gt::html(
      "<b>Table A1.</b><br>
      Unadjusted regression analyses."
    ),
    adjusted = gt::html(
      "<b>Table A2.</b><br>
      Regression analyses adjusted using the back-door criterion (DAG in Figure 1)."
    ),
    transformed = gt::html(
      "<b>Table A3.</b><br>
      Back-door adjusted analyses with continuous outcomes transformed to meet the
      normality assumption."
    ),
    `g-computation` = gt::html(
      "<b>Table A4.</b><br>
      Back-door adjusted, transformed-outcome analyses evaluated via g-computation
      after propensity-score matching."
    ),
    `g-computation_plus` = gt::html(
      "<b>Table A5.</b><br>
      Back-door adjusted, normality-transformed analyses with additional adjustment
      for diabetes and hypertension, evaluated via g-computation after propensity-score
      matching."
    )
  )
  lapply(rlang::set_names(names(t0)), function(i) {
    g <- ifelse(stringr::str_detect(i, "g-computation"), TRUE, FALSE)
    table_single(
      t0[[i]],
      gcomp = g,
      title = titles[[i]]
    )
  })
}
